const data = $input.first().json;
const specs = data.specs || [];
const alertas = specs.map(s => ({
  tipo: 'cypress',
  spec: s.spec ? s.spec.split('/').pop().split('\\').pop() : 'desconocido',
  fallos: s.fallos || 0,
  tests: (s.tests || []).map(t => ({
    titulo: t.titulo || t.title || '',
    error: String(t.error || '').substring(0, 200)
  }))
}));
return [{
  json: {
    fuente: 'cypress',
    icono: '🔴',
    titulo: 'FALLO CRÍTICO EN TEST',
    alertas,
    total: data.total_fallos_criticos || specs.length || 0,
    timestamp: data.timestamp || new Date().toISOString(),
    ambiente: data.ambiente || 'QA'
  }
}];

const data = $input.first().json;
const issues = data.issues || [];
const alertas = issues.map(issue => ({
  id: issue.key,
  titulo: issue.fields?.summary || 'Sin titulo',
  estado: issue.fields?.status?.name || 'N/A',
  prioridad: issue.fields?.priority?.name || 'Highest',
  reportadoPor: issue.fields?.reporter?.displayName || 'Desconocido',
  asignado: issue.fields?.assignee?.displayName || 'Sin asignar',
  created: issue.fields?.created || new Date().toISOString()
}));
return [{
  json: {
    fuente: 'jira',
    icono: '🚨',
    titulo: 'BUG HIGHEST EN JIRA',
    alertas,
    total: issues.length,
    timestamp: new Date().toISOString(),
    ambiente: 'QA'
  }
}];

const data = $input.first().json;
const ahora = new Date(data.timestamp);
const hora = ahora.toLocaleTimeString('es-CL', { timeZone: 'America/Santiago', hour: '2-digit', minute: '2-digit' });
const fecha = ahora.toLocaleDateString('es-CL', { timeZone: 'America/Santiago' });

let mensajeWA = '', htmlEmail = '', asunto = '';

if (data.fuente === 'cypress') {
  const item = data.alertas[0] || {};
  const test = (item.tests || [])[0] || {};
  mensajeWA = data.icono + ' FALLO CRITICO QA — Bupa Chile\n\n'
    + '📁 Spec: ' + (item.spec || 'N/A') + '\n'
    + '❌ Test: ' + (test.titulo || 'N/A') + '\n'
    + '⚠️ Error: ' + (test.error || 'Ver logs') + '\n'
    + '🕐 Hora: ' + hora + ' hrs | Ambiente: QA\n\nRevisar inmediatamente.';
  htmlEmail = '<h2 style="color:#c0392b;font-family:Arial">🔴 Fallo Critico QA — Bupa Chile</h2>'
    + '<table style="border-collapse:collapse;width:100%;font-family:Arial">'
    + '<tr><td style="padding:8px;background:#f8d7da"><b>Spec:</b></td><td style="padding:8px">' + item.spec + '</td></tr>'
    + '<tr><td style="padding:8px;background:#f8d7da"><b>Test:</b></td><td style="padding:8px">' + test.titulo + '</td></tr>'
    + '<tr><td style="padding:8px;background:#f8d7da"><b>Error:</b></td><td style="padding:8px;font-family:monospace;color:#c0392b">' + test.error + '</td></tr>'
    + '<tr><td style="padding:8px;background:#f8d7da"><b>Hora:</b></td><td style="padding:8px">' + hora + ' hrs — ' + fecha + '</td></tr>'
    + '</table><p style="font-family:Arial;color:#666;margin-top:16px">Mensaje automatico — QA Bupa Chile</p>';
  asunto = '🔴 Fallo Critico QA — ' + (item.spec || 'spec') + ' — ' + hora + ' hrs';

} else {
  const statusColor = (s) => ({ 'To Do':'#e74c3c','In Progress':'#e67e22','Design':'#9b59b6','Testing':'#3498db','Review':'#2980b9' }[s] || '#95a5a6');

  const lineas = data.alertas.map(a =>
    '🎫 ' + a.id + ': ' + a.titulo + '\n'
    + '   📌 Estado: ' + a.estado + '\n'
    + '   👤 ' + a.asignado
  ).join('\n\n');
  mensajeWA = data.icono + ' BUG HIGHEST — Bupa Chile QA\n\n'
    + lineas + '\n\n🕐 ' + hora + ' hrs\n\nAsignar y atender de inmediato.';

  const tarjetas = data.alertas.map(a =>
    '<div style="border-left:4px solid #e67e22;padding:12px;margin:8px 0;font-family:Arial;background:#fffdf0">'
    + '<p style="margin:0 0 6px"><b>' + a.id + ':</b> ' + a.titulo + '</p>'
    + '<p style="margin:4px 0"><span style="background:' + statusColor(a.estado) + ';color:#fff;padding:2px 10px;border-radius:4px;font-size:12px;font-family:Arial">' + a.estado + '</span></p>'
    + '<p style="margin:6px 0;color:#555;font-size:13px;font-family:Arial">👤 ' + a.reportadoPor + ' → <b>' + a.asignado + '</b></p>'
    + '</div>'
  ).join('');

  htmlEmail = '<h2 style="color:#e67e22;font-family:Arial">🚨 Bugs Highest — Bupa Chile QA</h2>'
    + '<p style="font-family:Arial;color:#666">' + data.total + ' bug(s) Highest activos — ' + hora + ' hrs, ' + fecha + '</p>'
    + tarjetas
    + '<p style="font-family:Arial;color:#aaa;font-size:12px;margin-top:16px">Mensaje automatico — Sistema QA Bupa Chile</p>';
  asunto = '🚨 ' + data.total + ' Bug(s) Highest activos — Bupa Chile QA — ' + hora + ' hrs';
}

return [{ json: { mensajeWA: encodeURIComponent(mensajeWA), htmlEmail, asunto, fuente: data.fuente } }];
